/*******
 * '= CQP_REINSURANCE_DISTRIBUTION / CQP_TOTAL_FORTE_USD_AGG
 * By Adriana Centellas
 */

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}
// Get all possible amounts
const values = [
  this._parent.CQP_STORAGE_EXPOSURE?.[0]?.CQP_TOTAL_FORTE_USD_AGG,
  this._parent.CQP_STORAGE_EXPOSURE?.[0]?.CQP_TOTAL_FORTE_USD_EEL,
  this._parent.CQP_TRANSIT_EXPOSURE?.[0]?.CQP_MLI_TOTAL_FORTE_USD,
  this._parent.CQP_TRANSIT_EXPOSURE?.[0]?.CQP_MLE_TOTAL_FORTE_USD,
  this._parent.CQP_TRANSIT_EXPOSURE?.[0]?.CQP_MLD_TOTAL_FORTE_USD
];

// Convert safely to numbers
const numericValues = values.map(function(v){
  return safeNumber(v);
});

// Get the largest value
const amount = Math.max.apply(null, numericValues);

// Apply distribution
return (safeNumber(this.CQP_REINSURANCE_DISTRIBUTION) / 100) * amount;

